var e=JSON.parse(`[{"id":"L5_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"후후, 느려요. 너무 느립니다.","JPN":"ふふ、遅い。遅すぎです。","ENG":"Hah hah. Nice try, but you’re too slow.","TWN":"嘿嘿～太慢了，太慢了。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"박력은 넘치지만, 움직임이 단순하군요.","JPN":"迫力は溢れていますが、動きが単純ですね。","ENG":"You’ve got power, but your movements are too predictable.","TWN":"氣勢很足，但動作很容易被看破。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"DOMA_NPC_NULL_WARRIOR","text":{"KOREA":"이 일대는 전부 처리한 것 같습니다.","JPN":"この一帯はすべて片付けたようです。","ENG":"I think we’ve killed every last one of them here.","TWN":"這附近的好像都解決了。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"대결할 만한 상대가 없는 게 아쉽군요.","JPN":"対決できそうな相手がいないのが残念ですね。","ENG":"What a shame there wasn’t a worthy foe to duel this time.","TWN":"沒一個值得一戰的對手，真是遺憾啊。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"인간이 쳐들어온다고 해서 왔지만, 정작 인간 형상을 베낀 듯한 이런 흉물들뿐이라니.","JPN":"人間が攻撃してきたと言って来てみましたが、人間の形をしているこの醜いものだけだとは。","ENG":"I was excited to hear the humans have attacked, but only to be let down by these imposters in human skin.","TWN":"聽說人類要入侵才來的，結果卻只有這些擬人的怪物。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"DOMA_NPC_NULL_WARRIOR","text":{"KOREA":"음?","JPN":"うん？","ENG":"Mm?","TWN":"嗯？"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"DOMA_NPC_NULL_WARRIOR","text":{"KOREA":"이 녀석들의 팔에 뭔가 새겨져 있습니다.","JPN":"こいつらの腕に何かが刻み付けられています。","ENG":"There’s some kind of mark on their arms.","TWN":"這些傢伙的手臂上刻著什麼東西。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"DOMA_NPC_NULL_WARRIOR","text":{"KOREA":"처치한 놈들은 전부 이런 표식이 있는 것 같은데, 무슨 의미라도 있는 걸까요?","JPN":"やっつけたやつらは全部このような印があるみたいですけど、何か意味でもあるのでしょうか？","ENG":"I think they all have it. Do you think it means anything?","TWN":"被消滅的傢伙好像都有這種標記，這有什麼意義嗎？"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"이건…….","JPN":"これは……","ENG":"That’s...","TWN":"這是…"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"검은 역병에 걸린 인간들에게 새겨지는 추방자의 낙인이군요.","JPN":"黒い疫病にかかった人間に刻まれる追放者の烙印ですね。","ENG":"A brand marked to humans who’ve contracted the Black Plague.","TWN":"被黑死病感染的人類身上刻下的流放者的烙印。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"아무래도 이분들은 자신의 의지로 여기까지 온 게 아닌 것 같네요.","JPN":"どうやらこの方々は、自分の意志でここまで来たわけではないようです。","ENG":"Someone must have forced them to come here against their will.","TWN":"看來這些人不是自願來到這裡的。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"DOMA_NPC_NULL_WARRIOR","text":{"KOREA":"병자들을 이용해서 이곳을 공격할 생각을 하다니, 아무리 인간이라지만 끔찍한 발상이군요.","JPN":"病人を利用してここを攻撃しようとするとは、いくら人間であっても残酷な発想です。","ENG":"Using the sick as an army... What a nasty human way of thinking.","TWN":"竟然想著利用病人來攻擊這裡，這想法真可怕。雖然是人類，但也太殘忍了。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"DOMA_NPC_NULL_WARRIOR","text":{"KOREA":"검은 역병에 걸리면… 우리도 결국 이렇게 되고 마는 걸까요?","JPN":"黒い疫病にかかると……俺たちも結局こうなってしまうのでしょうか？","ENG":"If we also get the Black Plague... Do we also end up like this?","TWN":"如果感染了黑死病…我們最後也會變成這樣嗎？"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"…"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"자, 그런 걱정은 나중에. 우리에겐 아직 지켜야 할 것이 남아있잖습니까?","JPN":"さて、そのような心配は後でしてください。私たちにはまだ守るべきものが残っているではないですか。","ENG":"That’s a worry for another time. Right now, we have our duties to protect what’s ours.","TWN":"好了，現在想這些也沒用。我們還有需要守護的東西，不是嗎？"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"이만 돌아가도록 하죠.","JPN":"もう帰りましょう。","ENG":"Let’s head back.","TWN":"回去吧。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"DOMA_NPC_NULL_DOCTOR","text":{"KOREA":"도, 도마님… 해질 무렵부터 동생 분의 상태가 이상하더니…","JPN":"ど、ドマ様……夕方から妹さんの容態がおかしくなって……","ENG":"D-Doma...! Your sister... she suddenly started getting worse during sunset and...","TWN":"多，多馬先生…你妹妹從下午開始狀態就變得有點奇怪…"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"DOMA_NPC_NULL_DOCTOR","text":{"KOREA":"갑자기 모습이 검게 변해서… 어떤 냄새가 난다며 밖으로 뛰쳐나가셨어요.","JPN":"いきなり全身が黒くなっては……ある匂いがすると外に出ていきました。","ENG":"She ran out, saying she smelled something as she turned black.","TWN":"身體突然變黑了…又說聞到什麼味道，就跑出去了。"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"…"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"어느 방향으로 갔는지… 저에게 알려 주시겠습니까?","JPN":"どの方向に向かったのか……私に教えてくれませんか？","ENG":"Can you tell me which way she went?","TWN":"她往哪個方向去了？你能告訴我嗎？"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":null,"text":{"KOREA":"그거 알아, 오빠?","JPN":"それ知ってる？　兄さん。","ENG":"You know what, Doma?","TWN":"你知道嗎，哥哥？"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":null,"text":{"KOREA":"흡혈귀 전사들은 자신이 죽을 때가 되면, 함께 싸운 동료 전사나 자신이 인정한 호적수에게 그 심장을 먹게 해.","JPN":"吸血鬼の戦士は自分が死ぬ時になると、一緒に戦った戦士の仲間や自分が認めた好敵手にその心臓を食わせるの。","ENG":"When a vampire warrior is about to die, they seek out their comrades or a formidable foe and have their heart consumed.","TWN":"吸血鬼戰士在臨死之際，會讓與自己並肩作戰的戰友，或自己認可的對手吃掉自己的心臟。"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":null,"text":{"KOREA":"그렇게 하면, 두 사람 모두 치명상을 입더라도 한 명은 살 수 있게 되거든.","JPN":"そうすると、二人とも致命傷を負っても一人は生き残れるから。","ENG":"That way, when both get badly injured, at least one of them can survive.","TWN":"這樣的話，即使兩個人都受了致命傷，也能保住一個人的性命。"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":null,"text":{"KOREA":"삶은 영원하지 못하더라도, 심장을 통해 영혼만은 영원히 누군가를 통해 이어가게 되는 거야.","JPN":"人生は永遠でなくても、心臓を通じて魂だけは永遠に誰かを通じて繋がれるんだよ。","ENG":"Although life does not last forever, the soul within the heart does.","TWN":"即使生命不是永恆的，靈魂也會透過心臟永遠傳承給某個人。"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":null,"text":{"KOREA":"미신이라는 것쯤은 알지만, 그래도 멋진 이야기지 않아?","JPN":"迷信ってことくらいはわかってるけど、それでも素敵な話だと思わない？","ENG":"I realize it's a silly superstition, but isn't it wonderful still?","TWN":"雖然知道這只是迷信，但這故事不是很棒嗎？"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":null,"text":{"KOREA":"병이 나아서 오빠랑 전쟁터에 나가게 된다면, 나는 오빠에게 내 심장을 맡길게.","JPN":"病気が治って兄さんと戦場に出ることになったら、私は兄さんに私の心臓を託すよ。","ENG":"If I ever beat this disease and go out on the battlefield with you, I want you to take my heart.","TWN":"如果我病好了能和哥哥一起上戰場的話，我會把我的心臟交給哥哥。"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};